#include <unordered_set>

using namespace std;

long long solve(string s, vector<long long> order, long long k) {
    long long n = s.size();
    unordered_set<long long> marked;
    long long total = 0;

    for (long long t = 0; t < n; ++t) {
        long long pos = order[t];
        marked.insert(pos);

        long long left = pos;
        while (left >= 0 && s[left] != '*') {
            left--;
        }

        long long right = pos;
        while (right < n && s[right] != '*') {
            right++;
        }

        long long left_segment = pos - left;
        long long right_segment = right - pos;
        total += left_segment * right_segment;

        if (total >= k) {
            return t;
        }

        s[pos] = '*';
    }

    return -1;
}

